const response = $input.first().json;
const text = response.content?.[0]?.text || '{}';
let topic;
try {
  const jsonMatch = text.match(/\{[\s\S]*?\}/);
  topic = JSON.parse(jsonMatch[0]);
} catch(e) {
  topic = { topic_number: 1, title: 'Warum Handwerker 30 Prozent mehr Auftraege verlieren ohne Telefonassistenz', slug: 'handwerker-verpasste-anrufe', category: 'Branche', excerpt: 'Verpasste Anrufe kosten Handwerksbetriebe Tausende Euro im Jahr.' };
}
const today = new Date();
const months = ['Januar','Februar','M\u00e4rz','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];
const dateStr = today.getDate() + '. ' + months[today.getMonth()] + ' ' + today.getFullYear();
const isoDate = today.toISOString().split('T')[0];
return [{ json: { ...topic, dateStr, isoDate } }];

const response = $input.first().json;
const articleHtml = response.content?.[0]?.text || '';
const slug = $('Thema parsen').first().json.slug;
const title = $('Thema parsen').first().json.title;
const category = $('Thema parsen').first().json.category;
const dateStr = $('Thema parsen').first().json.dateStr;
const isoDate = $('Thema parsen').first().json.isoDate;
const excerpt = $('Thema parsen').first().json.excerpt;
const articleBase64 = Buffer.from(articleHtml, 'utf-8').toString('base64');
const images = ['nora-buero.png','nora-handwerk-neu.png','nora-zahnarzt.png','nora-architekt.png','nora-friseur.png','nora-physiotherapie.png','nora-elektro.png','nora-beautysalon.png'];
const cardImage = images[Math.floor(Math.random() * images.length)];
const newCard = '
        <a href="./' + slug + '/" class="blog-card reveal">
          <div class="blog-card-img">
            <img src="../images/' + cardImage + '" alt="' + title.replace(/"/g,'') + '">
          </div>
          <div class="blog-card-body">
            <div class="blog-card-meta">
              <span class="blog-card-category">' + category + '</span>
              <span class="blog-card-date">' + dateStr + '</span>
            </div>
            <h2 class="blog-card-title">' + title + '</h2>
            <p class="blog-card-excerpt">' + excerpt + '</p>
            <span class="blog-card-link">Weiterlesen &rarr;</span>
          </div>
        </a>';
const newSchema = '      {
        "@type": "BlogPosting",
        "headline": "' + title.replace(/"/g,'') + '",
        "datePublished": "' + isoDate + '",
        "description": "' + excerpt.replace(/"/g,'') + '",
        "url": "https://fonora.ai/blog/' + slug + '/",
        "author": { "@type": "Person", "name": "Olga Reyes-Busch" }
      }';
const sitemapEntry = '  <url>
    <loc>https://fonora.ai/blog/' + slug + '/</loc>
    <changefreq>monthly</changefreq>
    <priority>0.7</priority>
  </url>';
return [{ json: { slug, title, articleBase64, newCard, newSchema, sitemapEntry } }];

const blogData = $input.first().json;
const sha = blogData.sha;
const content = Buffer.from(blogData.content, 'base64').toString('utf-8');
const newCard = $('Dateien vorbereiten').first().json.newCard;
const newSchema = $('Dateien vorbereiten').first().json.newSchema;
let updated = content.replace('<div class="blog-grid">', '<div class="blog-grid">' + newCard);
updated = updated.replace('"blogPost": [', '"blogPost": [\n' + newSchema + ',');
const updatedBase64 = Buffer.from(updated, 'utf-8').toString('base64');
return [{ json: { sha, updatedBase64 } }];

const sitemapData = $input.first().json;
const sha = sitemapData.sha;
const content = Buffer.from(sitemapData.content, 'base64').toString('utf-8');
const newEntry = $('Dateien vorbereiten').first().json.sitemapEntry;
const updated = content.replace('</urlset>', newEntry + '\n</urlset>');
const updatedBase64 = Buffer.from(updated, 'utf-8').toString('base64');
return [{ json: { sha, updatedBase64 } }];
